#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N>=666 && N<=888) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

